// Robust context pick: Claim Next can return 2 rows (reset + claim). Pick the row that actually has queue_id.
const claimItems = $items('🔒 Claim Next') || [];
const claimItem = claimItems.find(i => i.json && i.json.queue_id) || claimItems[claimItems.length - 1] || { json: {} };
const queueData = claimItem.json;

const downloadItem = $('📥 Download File').first();
const downloadJson = downloadItem?.json || {};
const downloadBinary = downloadItem?.binary || {};

// File metadata
const fileName = queueData.file_name || downloadJson.name || 'UNKNOWN';
const mimeType = queueData.mime_type || downloadJson.mimeType || 'application/pdf';
const driveFileId = queueData.drive_file_id || downloadJson.id || '';
const queueId = queueData.queue_id;

// Claude response (success output of Claude Vision)
const claudeResponse = $input.first().json;

// Generate invoice ID
const invoiceId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c === 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

// Extension bestimmen
let extension = 'pdf';
if (mimeType && mimeType.includes('image/jpeg')) extension = 'jpg';
else if (mimeType && mimeType.includes('image/png')) extension = 'png';
else if (mimeType && mimeType.includes('image/webp')) extension = 'webp';

const storagePath = `receipts/${invoiceId}.${extension}`;

return {
  json: {
    queue_id: queueId,
    invoice_id: invoiceId,
    original_filename: fileName,
    mime_type: mimeType,
    extension: extension,
    storage_path: storagePath,
    storage_filename: `${invoiceId}.${extension}`,
    drive_file_id: driveFileId,
    claude_response: claudeResponse
  },
  binary: downloadBinary
};

// Parse Claude response and merge with upload data
const uploadData = $('🔧 Prepare Upload').first().json;

// Get Claude response
const claudeNode = $('🤖 Claude Vision').first().json;
let claudeResponse;
if (claudeNode.content && Array.isArray(claudeNode.content)) {
  claudeResponse = claudeNode.content[0]?.text;
} else {
  claudeResponse = claudeNode.content || claudeNode.text || JSON.stringify(claudeNode);
}

// Clean response - remove markdown
let cleanJson = claudeResponse;
if (typeof cleanJson === 'string') {
  cleanJson = cleanJson.replace(/```json\s*/gi, '');
  cleanJson = cleanJson.replace(/```\s*/g, '');
  cleanJson = cleanJson.trim();
}

let parsed;
try {
  parsed = JSON.parse(cleanJson);
} catch (e) {
  throw new Error(`JSON Parse Error: ${e.message}\n\nRaw:\n${cleanJson.substring(0, 500)}`);
}

// V2: Smart net/gross handling - trust Claude when both provided, fallback to calculation
const vatPercent = parsed.rechnung?.mwst_prozent || 19;
const rawGross = Number(parsed.rechnung?.summe_brutto) || 0;
const rawNet = Number(parsed.rechnung?.summe_netto) || 0;

let grossAmount, netAmount;

if (rawNet > 0 && rawGross > 0) {
  // Both provided — validate plausibility
  const expectedGross = Math.round(rawNet * (1 + vatPercent / 100) * 100) / 100;
  if (Math.abs(expectedGross - rawGross) < 1.0) {
    grossAmount = rawGross;
    netAmount = rawNet;
  } else {
    // Inconsistent — trust brutto (Endpreis)
    grossAmount = rawGross;
    netAmount = Math.round((rawGross / (1 + vatPercent / 100)) * 100) / 100;
  }
} else if (rawGross > 0) {
  grossAmount = rawGross;
  netAmount = Math.round((rawGross / (1 + vatPercent / 100)) * 100) / 100;
} else if (rawNet > 0) {
  netAmount = rawNet;
  grossAmount = Math.round(rawNet * (1 + vatPercent / 100) * 100) / 100;
} else {
  grossAmount = 0;
  netAmount = 0;
}

// Type mapping
const typeMapping = {
  'BAUMARKT': 'BAUMARKT',
  'GROSSHANDEL': 'GROSSHANDEL',
  'FACHHANDEL': 'FACHHANDEL',
  'HERSTELLER': 'HERSTELLER',
  'ONLINE': 'ONLINE',
  'TANKSTELLE': 'SONSTIGE',
  'RESTAURANT': 'SONSTIGE',
  'SOFTWARE': 'SONSTIGE',
  'SONSTIGE': 'SONSTIGE'
};

// Escape SQL
const escapeSql = (str) => str ? String(str).replace(/'/g, "''") : '';

// Supplier code
let supplierCode = parsed.lieferant?.code || parsed.lieferant?.name?.substring(0, 4) || 'UNBK';
supplierCode = supplierCode.toUpperCase().replace(/[^A-Z]/g, '').substring(0, 4);
if (supplierCode.length < 2) supplierCode = 'UNBK';

// Payment data with defaults
const zahlung = parsed.zahlung || {};
const rechnungsDatum = parsed.rechnung?.datum || new Date().toISOString().split('T')[0];
const zahlungszielTage = zahlung.zahlungsziel_tage || 14;

// Calculate due date if not provided
let faelligAm = zahlung.faellig_am;
if (!faelligAm) {
  const d = new Date(rechnungsDatum);
  d.setDate(d.getDate() + zahlungszielTage);
  faelligAm = d.toISOString().split('T')[0];
}

return {
  queue_id: uploadData.queue_id,
  invoice_id: uploadData.invoice_id,
  storage_path: uploadData.storage_path,
  original_filename: uploadData.original_filename,
  drive_file_id: uploadData.drive_file_id,

  // Supplier
  lieferant_name: parsed.lieferant?.name || 'UNBEKANNT',
  lieferant_name_escaped: escapeSql(parsed.lieferant?.name || 'UNBEKANNT'),
  lieferant_code: supplierCode,
  lieferant_typ: typeMapping[parsed.lieferant?.typ] || 'SONSTIGE',

  expense_category: parsed.expense_category || 'MATERIAL',

  // Invoice
  rechnung_nummer: parsed.rechnung?.nummer || `SCAN-${uploadData.invoice_id.substring(0, 8)}`,
  rechnung_datum: rechnungsDatum,
  summe_brutto: grossAmount,
  summe_netto: netAmount,
  mwst_prozent: vatPercent,

  // Payment
  payment_iban: zahlung.iban || '',
  payment_bic: zahlung.bic || '',
  payment_terms_days: zahlungszielTage,
  due_date: faelligAm,
  discount_percent: zahlung.skonto_prozent || 0,
  discount_days: zahlung.skonto_tage || 0,

  // Positions
  positionen: parsed.positionen || [],
  positionen_count: (parsed.positionen || []).length,

  needs_assignment: ['MATERIAL', 'SUBCONTRACTOR', 'ENTERTAINMENT'].includes(parsed.expense_category)
};

